import React, { useState } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  Stepper,
  Step,
  StepLabel,
  StepButton,
  LinearProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import EditIcon from '@mui/icons-material/Edit';
import SendIcon from '@mui/icons-material/Send';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import TipsAndUpdatesIcon from '@mui/icons-material/TipsAndUpdates';
import VerifiedIcon from '@mui/icons-material/Verified';
import CelebrationOutlinedIcon from '@mui/icons-material/CelebrationOutlined';
import MoneyOffIcon from '@mui/icons-material/MoneyOff';
import SpeedIcon from '@mui/icons-material/Speed';
import PeopleIcon from '@mui/icons-material/People';
import ThumbDownAltIcon from '@mui/icons-material/ThumbDownAlt';
import WarningIcon from '@mui/icons-material/Warning';
import TrendingDownIcon from '@mui/icons-material/TrendingDown';

const TestimonialMascot = ({ size = 'medium', color = 'primary' }) => {
  const theme = useTheme();
  const sizeMap = {
    small: { width: 40, height: 40, quoteSize: 'small' },
    medium: { width: 60, height: 60, quoteSize: 'medium' },
    large: { width: 80, height: 80, quoteSize: 'large' }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Speech bubble shape */}
      <Box
        sx={{
          width: '100%',
          height: '100%',
          borderRadius: '50%',
          background: theme => theme.palette[color].main,
          position: 'relative',
          '&::after': {
            content: '""',
            position: 'absolute',
            bottom: '-10px',
            right: '10px',
            width: '20px',
            height: '20px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.5)'
          },
          '&::before': {
            content: '""',
            position: 'absolute',
            bottom: '-18px',
            right: '0',
            width: '15px',
            height: '15px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.3)'
          }
        }}
      />

      {/* Quote icon */}
      <FormatQuoteIcon 
        sx={{ 
          position: 'absolute', 
          color: 'white',
          transform: 'rotate(180deg)',
          fontSize: dims.quoteSize === 'small' ? '1.5rem' : 
                   dims.quoteSize === 'medium' ? '2rem' : '2.5rem'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          left: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          right: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '30%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '20px',
          height: '10px',
          borderBottomLeftRadius: '10px',
          borderBottomRightRadius: '10px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const TestimonialStarMascot = ({ size = 'medium', color = 'primary' }) => {
  const sizeMap = {
    small: { width: 40, height: 40 },
    medium: { width: 60, height: 60 },
    large: { width: 80, height: 80 }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Star shape */}
      <StarIcon 
        sx={{ 
          position: 'absolute',
          width: '100%',
          height: '100%',
          color: theme => theme.palette[color].main,
          filter: 'drop-shadow(0 2px 5px rgba(0,0,0,0.2))'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          left: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          right: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '35%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '16px',
          height: '8px',
          borderBottomLeftRadius: '8px',
          borderBottomRightRadius: '8px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [activeStep, setActiveStep] = useState(0);
  const [completed, setCompleted] = useState({});
  const [originalScores, setOriginalScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [enhancedScores, setEnhancedScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [spotlightActive, setSpotlightActive] = useState(false);

  const steps = [
    'Enter original testimonial',
    'Get AI enhancement',
    'Client verification'
  ];

  const originalText = "The coaching was good. I learned some things that helped me.";
  const enhancedText = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  const handleStep = (step) => () => {
    setActiveStep(step);

    // Mark previous steps as completed
    const newCompleted = {...completed};
    for (let i = 0; i < step; i++) {
      newCompleted[i] = true;
    }
    setCompleted(newCompleted);
  };

  const handleNext = () => {
    const newCompleted = {...completed};
    newCompleted[activeStep] = true;
    setCompleted(newCompleted);
    setActiveStep((prevActiveStep) => prevActiveStep + 1);
  };

  const handleReset = () => {
    setActiveStep(0);
    setCompleted({});
    setOriginalScores({ emotional: 0, specificity: 0, credibility: 0 });
    setEnhancedScores({ emotional: 0, specificity: 0, credibility: 0 });
    setSpotlightActive(false);
  };

  const getScoreColor = (score) => {
    if (score < 50) return 'error.main';
    if (score < 75) return 'warning.main';
    return 'success.main';
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{ 
          pt: { xs: 6, md: 10 }, 
          pb: { xs: 8, md: 12 },
          background: 'linear-gradient(180deg, #F9FAFB 0%, #FFFFFF 100%)'
        }}
      >
        <Container maxWidth="lg">
          <Grid container spacing={4} alignItems="center">
            <Grid item xs={12} md={6}>
              <Box sx={{ mb: 4 }}>
                <Typography 
                  variant="h2" 
                  component="h1" 
                  sx={{ 
                    fontWeight: 800, 
                    mb: 2,
                    fontSize: { xs: '2.5rem', md: '3.5rem' },
                    lineHeight: 1.2
                  }}
                >
                  <Box component="span" sx={{ color: 'primary.main' }}>Weak testimonials</Box> are costing you clients
                </Typography>

                <Typography 
                  variant="h5" 
                  color="text.secondary" 
                  sx={{ 
                    mb: 4,
                    fontWeight: 400,
                    lineHeight: 1.5
                  }}
                >
                  Transform vague praise into powerful social proof that converts skeptics into paying clients—in seconds.
                </Typography>

                <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                  <Button 
                    variant="contained" 
                    size="large" 
                    component={RouterLink}
                    to="/enhance"
                    sx={{ 
                      py: 1.5, 
                      px: 4, 
                      borderRadius: 2,
                      fontSize: '1rem'
                    }}
                  >
                    Boost Your Testimonials
                  </Button>

                  <Button 
                    variant="outlined" 
                    size="large"
                    onClick={handleReset}
                    sx={{ 
                      py: 1.5, 
                      px: 4, 
                      borderRadius: 2,
                      fontSize: '1rem'
                    }}
                  >
                    Try Demo
                  </Button>
                </Stack>

                <Box sx={{ mt: 4, display: 'flex', alignItems: 'center' }}>
                  <Box sx={{ display: 'flex' }}>
                    {[...Array(5)].map((_, i) => (
                      <StarIcon key={i} sx={{ color: '#F59E0B', fontSize: 20 }} />
                    ))}
                  </Box>
                  <Typography variant="body2" sx={{ ml: 1, color: 'text.secondary' }}>
                    4.9/5 from 200+ users
                  </Typography>
                </Box>
              </Box>
            </Grid>

            {/* Demo section remains the same */}
          </Grid>
        </Container>
      </Box>

      {/* Problem Section */}
      <Box sx={{ py: 10, bgcolor: 'grey.50' }}>
        <Container maxWidth="lg">
          <Box sx={{ textAlign: 'center', mb: 8 }}>
            <Typography 
              variant="h3" 
              component="h2" 
              sx={{ 
                fontWeight: 700, 
                mb: 2 
              }}
            >
              The Painful Truth About Your Testimonials
            </Typography>

            <Typography 
              variant="h6" 
              color="text.secondary" 
              sx={{ 
                maxWidth: 700, 
                mx: 'auto' 
              }}
            >
              Most testimonials fail to convert because they lack the three critical elements that drive sales.
            </Typography>
          </Box>

          <Grid container spacing={4}>
            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  p: 4, 
                  height: '100%', 
                  borderRadius: 4,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <ThumbDownAltIcon 
                  sx={{ 
                    fontSize: 40, 
                    color: 'error.main', 
                    mb: 2 
                  }} 
                />
                <Typography variant="h5" gutterBottom fontWeight={600}>
                  Generic Praise Falls Flat
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  "Great service!" and "Highly recommend!" testimonials are ignored by potential clients because they sound fake and lack substance.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  p: 4, 
                  height: '100%', 
                  borderRadius: 4,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <WarningIcon 
                  sx={{ 
                    fontSize: 40, 
                    color: 'warning.main', 
                    mb: 2 
                  }} 
                />
                <Typography variant="h5" gutterBottom fontWeight={600}>
                  Missing Specificity Kills Trust
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Without concrete details and specific results, potential clients remain skeptical and unconvinced that you can help them.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  p: 4, 
                  height: '100%', 
                  borderRadius: 4,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <TrendingDownIcon 
                  sx={{ 
                    fontSize: 40, 
                    color: 'error.main', 
                    mb: 2 
                  }} 
                />
                <Typography variant="h5" gutterBottom fontWeight={600}>
                  Low Conversion = Lost Revenue
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Every weak testimonial on your site is actively driving away potential clients and costing you thousands in lost revenue.
                </Typography>
              </Card>
            </Grid>
          </Grid>

          <Box 
            sx={{ 
              mt: 8, 
              p: 4, 
              bgcolor: 'error.light', 
              borderRadius: 4,
              border: '1px solid',
              borderColor: 'error.main',
              maxWidth: 800,
              mx: 'auto'
            }}
          >
            <Typography variant="h6" color="error.dark" fontWeight={600} gutterBottom>
              The Costly Reality:
            </Typography>
            <Typography variant="body1" color="error.dark">
              Studies show that 88% of consumers trust testimonials as much as personal recommendations, but only when they contain specific details and authentic emotion. Generic testimonials can actually harm your credibility.
            </Typography>
          </Box>
        </Container>
      </Box>

      {/* Solution Section */}
      <Box sx={{ py: 10 }}>
        <Container maxWidth="lg">
          <Box sx={{ textAlign: 'center', mb: 8 }}>
            <Typography 
              variant="h3" 
              component="h2" 
              sx={{ 
                fontWeight: 700, 
                mb: 2 
              }}
            >
              Transform Bland Praise Into Powerful Stories
            </Typography>

            <Typography 
              variant="h6" 
              color="text.secondary" 
              sx={{ 
                maxWidth: 700, 
                mx: 'auto' 
              }}
            >
              TestiBoost uses advanced AI to enhance your testimonials with the three elements that drive conversions.
            </Typography>
          </Box>

          <Grid container spacing={4}>
            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  p: 4, 
                  height: '100%', 
                  borderRadius: 4,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  bgcolor: 'primary.light',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(99, 102, 241, 0.2)'
                  }
                }}
              >
                <SpeedIcon 
                  sx={{ 
                    fontSize: 40, 
                    color: 'primary.main', 
                    mb: 2 
                  }} 
                />
                <Typography variant="h5" gutterBottom fontWeight={600} color="primary.dark">
                  Emotional Impact
                </Typography>
                <Typography variant="body1" color="primary.dark">
                  Our AI infuses testimonials with authentic emotion that creates powerful connections with potential clients.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  p: 4, 
                  height: '100%', 
                  borderRadius: 4,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  bgcolor: 'secondary.light',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(139, 92, 246, 0.2)'
                  }
                }}
              >
                <VerifiedUserIcon 
                  sx={{ 
                    fontSize: 40, 
                    color: 'secondary.main', 
                    mb: 2 
                  }} 
                />
                <Typography variant="h5" gutterBottom fontWeight={600} color="secondary.dark">
                  Specific Results
                </Typography>
                <Typography variant="body1" color="secondary.dark">
                  We extract and highlight concrete outcomes, metrics, and transformations that prove your value.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  p: 4, 
                  height: '100%', 
                  borderRadius: 4,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  bgcolor: 'success.light',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(16, 185, 129, 0.2)'
                  }
                }}
              >
                <PeopleIcon 
                  sx={{ 
                    fontSize: 40, 
                    color: 'success.main', 
                    mb: 2 
                  }} 
                />
                <Typography variant="h5" gutterBottom fontWeight={600} color="success.dark">
                  Authentic Voice
                </Typography>
                <Typography variant="body1" color="success.dark">
                  Our AI preserves your client's unique voice while enhancing clarity and persuasiveness.
                </Typography>
              </Card>
            </Grid>
          </Grid>

          <Box 
            sx={{ 
              mt: 8, 
              p: 4, 
              bgcolor: 'success.light', 
              borderRadius: 4,
              border: '1px solid',
              borderColor: 'success.main',
              maxWidth: 800,
              mx: 'auto'
            }}
          >
            <Typography variant="h6" color="success.dark" fontWeight={600} gutterBottom>
              The TestiBoost Advantage:
